/**
 * ARIA Fallback Chain — six-tier cascade that determines how ARIA responds
 * when the LLM is unavailable or degraded.
 *
 * ## Fallback Tiers (evaluated in priority order)
 *
 * 1. **NO_NETWORK**    — Browser is offline (navigator.onLine === false).
 *                        ARIA uses heuristic analysis. No API call attempted.
 *
 * 2. **RATE_LIMITED**   — Too many LLM requests in a short window (MIN_INTERVAL_MS).
 *                        ARIA uses heuristic/canned response. Request is not queued.
 *
 * 3. **OVER_BUDGET**    — Rolling 24h token budget exceeded.
 *                        ARIA uses heuristic analysis until budget resets.
 *
 * 4. **SLOW_RESPONSE**  — LLM call timed out (exceeded LLM_TIMEOUT_MS).
 *                        Partial result discarded; heuristic fallback used.
 *
 * 5. **ERROR**          — LLM call failed (network error, HTTP 4xx/5xx, malformed response).
 *                        ARIA uses heuristic fallback and logs the error.
 *
 * 6. **ALL_CLEAR**      — LLM is reachable and within budget. Use live response.
 *
 * Every ARIA analysis path (player query, anomaly analysis, auto-briefing,
 * faction contact, inbox triage, commander delegation) must produce a
 * meaningful response regardless of which tier is active.
 */

/**
 * The six fallback tiers, ordered from most restrictive to least.
 * Each tier describes *why* the LLM is unavailable.
 */
export type FallbackTier =
  | 'no_network'
  | 'rate_limited'
  | 'over_budget'
  | 'slow_response'
  | 'error'
  | 'all_clear';

/** Timeout for LLM API calls in milliseconds (15 seconds). */
export const LLM_TIMEOUT_MS = 15_000;

/**
 * Determine the current fallback tier before attempting an LLM call.
 * This checks pre-call conditions only (tiers 1-3, 6).
 * Tiers 4 (slow_response) and 5 (error) are determined at call time.
 *
 * @param hasKey     — Whether an API key is configured
 * @param overBudget — Whether the 24h token budget is exceeded
 * @param rateLimited — Whether the rate limiter would block this request
 * @returns The active fallback tier
 */
export function determineFallbackTier(
  hasKey: boolean,
  overBudget: boolean,
  rateLimited: boolean,
): FallbackTier {
  // Tier 1: No network connectivity
  // Check navigator.onLine explicitly — in Node.js it may be undefined
  if (typeof navigator !== 'undefined' && navigator.onLine === false) {
    return 'no_network';
  }

  // No API key is equivalent to no network — can't reach LLM
  if (!hasKey) {
    return 'no_network';
  }

  // Tier 2: Rate limited
  if (rateLimited) {
    return 'rate_limited';
  }

  // Tier 3: Over budget
  if (overBudget) {
    return 'over_budget';
  }

  // Tier 6: All clear — LLM is available
  return 'all_clear';
}

/**
 * Wrap an LLM call with timeout protection.
 * Returns the LLM result on success, or throws with a distinguishable
 * error for timeout vs other failures.
 */
export async function withLlmTimeout<T>(
  llmCall: Promise<T>,
  timeoutMs: number = LLM_TIMEOUT_MS,
): Promise<T> {
  let timer: ReturnType<typeof setTimeout>;
  const timeout = new Promise<never>((_, reject) => {
    timer = setTimeout(() => reject(new LlmTimeoutError(timeoutMs)), timeoutMs);
  });

  try {
    const result = await Promise.race([llmCall, timeout]);
    clearTimeout(timer!);
    return result;
  } catch (err) {
    clearTimeout(timer!);
    throw err;
  }
}

/** Sentinel error class for LLM timeout detection. */
export class LlmTimeoutError extends Error {
  readonly timeoutMs: number;
  constructor(timeoutMs: number) {
    super(`LLM call timed out after ${timeoutMs}ms`);
    this.name = 'LlmTimeoutError';
    this.timeoutMs = timeoutMs;
  }
}

/**
 * Classify a caught error into a fallback tier.
 * Used after an LLM call fails to distinguish timeout from other errors.
 */
export function classifyError(err: unknown): 'slow_response' | 'error' {
  if (err instanceof LlmTimeoutError) {
    return 'slow_response';
  }
  return 'error';
}

/** Human-readable status messages for each fallback tier. */
export const TIER_STATUS_MESSAGES: Record<FallbackTier, string> = {
  no_network: 'ARIA offline — no network connection. Using onboard analysis.',
  rate_limited: 'ARIA rate-limited — too many recent queries. Using cached analysis.',
  over_budget: 'ARIA offline — daily token budget exceeded. Using onboard analysis.',
  slow_response: 'ARIA connection slow — LLM timed out. Using onboard analysis.',
  error: 'ARIA encountered an error — using onboard analysis.',
  all_clear: '',
};
