import type { ToolDef, ToolCall, ToolResult } from './commanderTools';
import { getGenericFallback } from './fallbacks';

/**
 * Core LLM provider interface.
 * All ARIA backends (Claude, Groq, Proxy, Heuristic) implement this.
 */
export interface ILlmProvider {
  readonly name: string;
  sendMessage(system: string, userMsg: string, maxTokens: number): Promise<string>;
}

/** Convenience alias — matches the task spec naming. */
export type LLMProvider = ILlmProvider;

/** Extended provider that supports Anthropic-style tool use */
export interface IToolProvider extends ILlmProvider {
  sendWithTools(
    system: string,
    userMsg: string,
    tools: ToolDef[],
    maxTokens: number,
  ): Promise<ToolUseResponse>;

  /** Continue a conversation after tool results */
  continueWithToolResults(
    system: string,
    messages: ToolMessage[],
    tools: ToolDef[],
    maxTokens: number,
  ): Promise<ToolUseResponse>;
}

export interface ToolUseResponse {
  /** Text content from the response (may be empty if only tool calls) */
  text: string;
  /** Tool calls the model wants to make */
  toolCalls: ToolCall[];
  /** Whether the model stopped because of end_turn vs tool_use */
  stopReason: 'end_turn' | 'tool_use' | 'max_tokens';
}

export type ToolMessage =
  | { role: 'user'; content: string }
  | { role: 'assistant'; content: ContentBlock[] }
  | { role: 'user'; content: ToolResultBlock[] };

interface ContentBlock {
  type: 'text' | 'tool_use';
  text?: string;
  id?: string;
  name?: string;
  input?: Record<string, unknown>;
}

interface ToolResultBlock {
  type: 'tool_result';
  tool_use_id: string;
  content: string;
  is_error?: boolean;
}

export type ProviderName = 'anthropic' | 'groq' | 'proxy' | 'heuristic';

class ClaudeProvider implements IToolProvider {
  readonly name = 'anthropic';
  constructor(private readonly apiKey: string) {}

  async sendMessage(system: string, userMsg: string, maxTokens: number): Promise<string> {
    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': this.apiKey,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: maxTokens,
        system,
        messages: [{ role: 'user', content: userMsg }],
      }),
    });
    if (!response.ok) throw new Error(`API error ${response.status}`);
    const data = (await response.json()) as { content: Array<{ type: string; text: string }> };
    const textBlock = data.content.find((c) => c.type === 'text');
    if (!textBlock) throw new Error('No text in response');
    return textBlock.text;
  }

  async sendWithTools(
    system: string,
    userMsg: string,
    tools: ToolDef[],
    maxTokens: number,
  ): Promise<ToolUseResponse> {
    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': this.apiKey,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: maxTokens,
        system,
        tools,
        messages: [{ role: 'user', content: userMsg }],
      }),
    });
    if (!response.ok) throw new Error(`API error ${response.status}`);
    return this.parseToolResponse(await response.json());
  }

  async continueWithToolResults(
    system: string,
    messages: ToolMessage[],
    tools: ToolDef[],
    maxTokens: number,
  ): Promise<ToolUseResponse> {
    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': this.apiKey,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: maxTokens,
        system,
        tools,
        messages,
      }),
    });
    if (!response.ok) throw new Error(`API error ${response.status}`);
    return this.parseToolResponse(await response.json());
  }

  private parseToolResponse(data: unknown): ToolUseResponse {
    const resp = data as {
      content: Array<{ type: string; text?: string; id?: string; name?: string; input?: Record<string, unknown> }>;
      stop_reason: string;
    };

    let text = '';
    const toolCalls: ToolCall[] = [];

    for (const block of resp.content) {
      if (block.type === 'text' && block.text) {
        text += block.text;
      } else if (block.type === 'tool_use' && block.id && block.name) {
        toolCalls.push({
          id: block.id,
          name: block.name,
          input: block.input ?? {},
        });
      }
    }

    const stopReason =
      resp.stop_reason === 'tool_use' ? 'tool_use'
        : resp.stop_reason === 'max_tokens' ? 'max_tokens'
          : 'end_turn';

    return { text, toolCalls, stopReason };
  }
}

class GroqProvider implements ILlmProvider {
  readonly name = 'groq';
  constructor(private readonly apiKey: string) {}

  async sendMessage(system: string, userMsg: string, maxTokens: number): Promise<string> {
    const response = await fetch('https://api.groq.com/openai/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${this.apiKey}`,
      },
      body: JSON.stringify({
        model: 'openai/gpt-oss-120b',
        max_tokens: maxTokens,
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: userMsg },
        ],
      }),
    });
    if (!response.ok) throw new Error(`API error ${response.status}`);
    const data = (await response.json()) as { choices: Array<{ message: { content: string } }> };
    if (!data.choices?.[0]?.message?.content) throw new Error('No text in response');
    return data.choices[0].message.content;
  }
}

/** Default proxy URL — overridden by VITE_PROXY_URL or localStorage */
let proxyBaseUrl = 'https://proxy.themultiverse.school';

export function setProxyBaseUrl(url: string): void {
  proxyBaseUrl = url.replace(/\/+$/, '');
}

export function getProxyBaseUrl(): string {
  return proxyBaseUrl;
}

class ProxyProvider implements ILlmProvider {
  readonly name = 'proxy';
  constructor(private readonly proxyKey: string) {}

  async sendMessage(system: string, userMsg: string, maxTokens: number): Promise<string> {
    const response = await fetch(`${proxyBaseUrl}/api/chat/completions`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${this.proxyKey}`,
        'X-Game': 'cotb',
      },
      body: JSON.stringify({
        model: 'openai/gpt-oss-120b',
        max_tokens: maxTokens,
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: userMsg },
        ],
      }),
    });
    if (!response.ok) throw new Error(`Proxy error ${response.status}`);
    const data = (await response.json()) as { choices: Array<{ message: { content: string } }> };
    if (!data.choices?.[0]?.message?.content) throw new Error('No text in proxy response');
    return data.choices[0].message.content;
  }
}

/**
 * Heuristic provider — returns canned fallback responses with no API call.
 * Valid `ILlmProvider` implementation for offline / budget-capped play.
 */
class HeuristicProvider implements ILlmProvider {
  readonly name = 'heuristic';

  async sendMessage(_system: string, userMsg: string, _maxTokens: number): Promise<string> {
    return getGenericFallback(userMsg);
  }
}

type ProviderFactory = (apiKey: string) => ILlmProvider;

const PROVIDER_REGISTRY = new Map<ProviderName, ProviderFactory>([
  ['anthropic', (key) => new ClaudeProvider(key)],
  ['groq', (key) => new GroqProvider(key)],
  ['proxy', (key) => new ProxyProvider(key)],
  ['heuristic', () => new HeuristicProvider()],
]);

export function createProvider(name: ProviderName, apiKey: string): ILlmProvider {
  const factory = PROVIDER_REGISTRY.get(name);
  if (!factory) throw new Error(`Unknown provider: ${name}`);
  return factory(apiKey);
}

/** Create a tool-capable provider. Only Anthropic supports tool use. */
export function createToolProvider(name: ProviderName, apiKey: string): IToolProvider | null {
  if (name !== 'anthropic') return null;
  return new ClaudeProvider(apiKey);
}

export function getRegisteredProviders(): ProviderName[] {
  return [...PROVIDER_REGISTRY.keys()];
}

/** Type guard for providers that support tool use */
export function isToolProvider(provider: ILlmProvider): provider is IToolProvider {
  return 'sendWithTools' in provider && typeof (provider as IToolProvider).sendWithTools === 'function';
}
