/**
 * Returns a fallback response for an anomaly discovery, selected deterministically by eid.
 */
export function getAnomalyFallback(anomalyType: number, asteroidEid: number): string {
  const responses = ANOMALY_RESPONSES[anomalyType] ?? ANOMALY_RESPONSES[1];
  const idx = Math.abs(asteroidEid) % responses.length;
  return responses[idx];
}

/**
 * Returns a generic fallback response for player queries, selected by hash of query.
 */
export function getGenericFallback(query: string): string {
  // Simple hash to pick deterministically
  let hash = 0;
  for (let i = 0; i < query.length; i++) {
    hash = (hash * 31 + query.charCodeAt(i)) >>> 0;
  }
  return GENERIC_RESPONSES[hash % GENERIC_RESPONSES.length];
}

export { ANOMALY_RESPONSES, GENERIC_RESPONSES };
