export interface UsageRecord {
  provider: string;
  model: string;
  inputTokens: number;
  outputTokens: number;
  timestamp: number;
}

export interface UsageSummary {
  tokensUsed: number;
  estimatedCostUsd: number;
  budgetCapTokens: number;
  budgetRemainingTokens: number;
  isOverBudget: boolean;
}

export interface SessionUsageSummary {
  inputTokens: number;
  outputTokens: number;
  totalTokens: number;
  budgetTokens: number;
  isOverBudget: boolean;
  /** True when the player has opted back in after exceeding the soft cap. */
  playerOptedIn: boolean;
}

const STORAGE_KEY = 'aria_usage';
const BUDGET_KEY = 'aria_budget_cap';
const DEFAULT_BUDGET_CAP = 10_000;
const WINDOW_MS = 24 * 60 * 60 * 1000;

/** Dollar value given to new players as ARIA inference credit. */
export const STARTING_INFERENCE_CREDIT_USD = 5.0;
/** Blended cost per token across providers (USD). */
export const BLENDED_COST_PER_TOKEN = 0.000006;
/** Starting token budget derived from the dollar credit. */
export const STARTING_TOKENS = Math.floor(STARTING_INFERENCE_CREDIT_USD / BLENDED_COST_PER_TOKEN);

// Rough per-token pricing in USD
const COST_PER_TOKEN: Record<string, { input: number; output: number }> = {
  anthropic: { input: 0.000003, output: 0.000015 },
  groq: { input: 0.00000059, output: 0.00000079 },
};

function loadRecords(): UsageRecord[] {
  if (typeof localStorage === 'undefined' || typeof localStorage.getItem !== 'function') return [];
  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return [];
  try {
    return JSON.parse(raw) as UsageRecord[];
  } catch {
    return [];
  }
}

function saveRecords(records: UsageRecord[]): void {
  if (typeof localStorage === 'undefined' || typeof localStorage.setItem !== 'function') return;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(records));
}

/** Returns only records within the rolling 24h window, discarding older entries. */
function getRecentRecords(): UsageRecord[] {
  const cutoff = Date.now() - WINDOW_MS;
  const all = loadRecords();
  const recent = all.filter((r) => r.timestamp >= cutoff);
  // Prune stale entries from storage
  if (recent.length < all.length) saveRecords(recent);
  return recent;
}

export function recordUsage(
  provider: string,
  model: string,
  inputTokens: number,
  outputTokens: number,
): void {
  const records = getRecentRecords();
  records.push({ provider, model, inputTokens, outputTokens, timestamp: Date.now() });
  saveRecords(records);
}

export function getBudgetCap(): number {
  if (typeof localStorage === 'undefined' || typeof localStorage.getItem !== 'function')
    return DEFAULT_BUDGET_CAP;
  const stored = localStorage.getItem(BUDGET_KEY);
  if (!stored) {
    // First launch — give new players the starting inference credit.
    localStorage.setItem(BUDGET_KEY, String(STARTING_TOKENS));
    return STARTING_TOKENS;
  }
  const parsed = parseInt(stored, 10);
  return Number.isNaN(parsed) || parsed <= 0 ? DEFAULT_BUDGET_CAP : parsed;
}

export function setBudgetCap(cap: number): void {
  if (typeof localStorage === 'undefined' || typeof localStorage.setItem !== 'function') return;
  localStorage.setItem(BUDGET_KEY, String(cap));
}

export function getUsageSummary(): UsageSummary {
  const records = getRecentRecords();
  const budgetCap = getBudgetCap();

  let tokensUsed = 0;
  let estimatedCostUsd = 0;

  for (const r of records) {
    tokensUsed += r.inputTokens + r.outputTokens;
    const pricing = COST_PER_TOKEN[r.provider] ?? COST_PER_TOKEN.anthropic;
    estimatedCostUsd += r.inputTokens * pricing.input + r.outputTokens * pricing.output;
  }

  return {
    tokensUsed,
    estimatedCostUsd,
    budgetCapTokens: budgetCap,
    budgetRemainingTokens: Math.max(0, budgetCap - tokensUsed),
    isOverBudget: tokensUsed >= budgetCap,
  };
}

/** Convert a token count to its approximate USD value using blended pricing. */
export function tokensToDollars(tokens: number): number {
  return tokens * BLENDED_COST_PER_TOKEN;
}

export function isOverBudget(): boolean {
  return getUsageSummary().isOverBudget;
}

/** Estimate input tokens from prompt text (4 chars ≈ 1 token). */
export function estimateInputTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

/** Estimate output tokens from response text (4 chars ≈ 1 token). */
export function estimateOutputTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

// ===================== Session-scoped token tracking =====================

const ENV_SESSION_BUDGET = (typeof import.meta !== 'undefined' && import.meta.env?.VITE_ARIA_TOKEN_BUDGET)
  ? parseInt(import.meta.env.VITE_ARIA_TOKEN_BUDGET as string, 10)
  : undefined;

const DEFAULT_SESSION_BUDGET = 50_000;

let sessionInputTokens = 0;
let sessionOutputTokens = 0;
let sessionPlayerOptedIn = false;

/** Record token usage for the current session (in-memory, resets on page reload). */
export function recordSessionUsage(inputTokens: number, outputTokens: number): void {
  sessionInputTokens += inputTokens;
  sessionOutputTokens += outputTokens;
}

/** Get the session token budget (from VITE_ARIA_TOKEN_BUDGET env var, default 50000). */
export function getSessionBudget(): number {
  return (ENV_SESSION_BUDGET != null && ENV_SESSION_BUDGET > 0)
    ? ENV_SESSION_BUDGET
    : DEFAULT_SESSION_BUDGET;
}

/** Get a summary of session token usage and budget status. */
export function getSessionUsageSummary(): SessionUsageSummary {
  const total = sessionInputTokens + sessionOutputTokens;
  const budget = getSessionBudget();
  return {
    inputTokens: sessionInputTokens,
    outputTokens: sessionOutputTokens,
    totalTokens: total,
    budgetTokens: budget,
    isOverBudget: total >= budget,
    playerOptedIn: sessionPlayerOptedIn,
  };
}

/**
 * Returns true when the session soft cap has been exceeded and the player
 * has NOT opted back in. This is the signal to fall back to heuristic mode.
 */
export function isSessionOverBudget(): boolean {
  if (sessionPlayerOptedIn) return false;
  const total = sessionInputTokens + sessionOutputTokens;
  return total >= getSessionBudget();
}

/** Player opts back in after exceeding the session soft cap. Resets the session counter. */
export function sessionOptBackIn(): void {
  sessionInputTokens = 0;
  sessionOutputTokens = 0;
  sessionPlayerOptedIn = true;
}

/** Reset session tracking (for testing). */
export function resetSessionUsage(): void {
  sessionInputTokens = 0;
  sessionOutputTokens = 0;
  sessionPlayerOptedIn = false;
}
